room_type_name as roomTypeName, user_id as userId, user_name as userName, user_mobile as userMobile,
bd_user_id as bdUserId, checkin_date as checkinDate, checkout_date as checkoutDate, night_count as nightCount,
room_count as roomCount, order_amount as orderAmount, tax_amount as taxAmount, discount_amount as discountAmount,
pay_amount as payAmount, refund_amount as refundAmount, order_status as orderStatus, refund_status as refundStatus,
refund_reason as refundReason, special_request as specialRequest, inner_remark as innerRemark, confirm_time as confirmTime,
checkin_time as checkinTime, checkout_time as checkoutTime, cancel_time as cancelTime, cancel_reason as cancelReason,
create_by as createBy, create_time as createTime, update_by as updateBy, update_time as updateTime
from hotel_order
where del_flag = '0'
and order_no = #{orderNo}
and hotel_id = #{hotelId}
and room_type_id = #{roomTypeId}
and order_status = #{orderStatus}
and user_id = #{userId}
and user_mobile like concat('%', #{userMobile}, '%')
and bd_user_id = #{bdUserId}
and date_format(create_time, '%Y-%m-%d') >= #{beginCreateTime}
and date_format(create_time, '%Y-%m-%d') <= #{endCreateTime}
and date_format(checkin_date, '%Y-%m-%d') >= #{beginCheckinDate}
and date_format(checkin_date, '%Y-%m-%d') <= #{endCheckinDate}
order by create_time desc

